import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize user input to prevent XSS
        HTMLEntityCodec htmlEncoder = ESAPI.encoder().getHTMLEntityCodec();
        String sanitizedName = htmlEncoder.encodeForHTML(name);

        System.out.println("Hello, " + sanitizedName + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
